# echo_core/conceptual_core/event_model_builder.py"""EventModelBuilder — превращает сырой Event Frame в полноценную EventModel.Часть реструктурированного ConceptualCore.Отвечает за достройку события: причинность, изменения состояний, последствия."""from typing import Optional, Dict, Anyfrom echo_core.core_types.event_model import EventModelclass EventModelBuilder:    """    Строит универсальную модель события из данных KnowledgeExtractor.    Достраивает недостающие звенья: что было до, что стало после, почему.    """    def __init__(self, concept_library, causal_graph):        self.concept_library = concept_library        self.causal_graph = causal_graph    def build(self, frame: Dict[str, Any], source: str = "text", source_type: str = "text") -> Optional[EventModel]:        """        Принимает сырой Event Frame от KnowledgeExtractor,        возвращает полноценную EventModel с достроенными связями.        """        if not frame or not isinstance(frame, dict):            return None        # Извлекаем базовые поля из фрейма        agent = frame.get("agent") or frame.get("actor") or frame.get("subject")        action = frame.get("action") or frame.get("verb")        obj = frame.get("object") or frame.get("target")        cause = frame.get("cause")        effect = frame.get("effect") or frame.get("result")        location = frame.get("location") or frame.get("place")        # Создаём базовую модель        event = EventModel(            agent=agent,            action=action,            object=obj,            location=location,            cause=cause,            effect=effect,            source=source,            source_type=source_type,            confidence=frame.get("confidence", 0.5)        )        # Достройка: пытаемся понять, что изменилось        self._infer_state_changes(event)        # Достройка: пытаемся найти причинно-следственные связи в графе        self._infer_causal_links(event)        return event    def _infer_state_changes(self, event: EventModel):        """        По действию и объекту пытается понять,        какое состояние было до и какое стало после.        """        if not event.object or not event.action:            return        # Находим концепт объекта        obj_concept = self.concept_library.find_by_name(event.object)        if not obj_concept:            return        # Проверяем известные переходы состояний по действию        action = event.action.lower() if event.action else ""        # Действия разрушения        if any(w in action for w in ("разбить", "сломать", "разрушить", "порвать", "уничтожить")):            event.before_state = "целый"            event.after_state = "разрушен"            event.effect = event.effect or f"{event.object} разрушен"        # Действия нагревания        elif any(w in action for w in ("нагреть", "нагревать", "разогреть", "подогреть")):            if obj_concept.has_property("состояние"):                current_state = obj_concept.properties.get("состояние", "")                if current_state == "твёрдое":                    event.before_state = "холодный"                    event.after_state = "горячий"                    event.effect = event.effect or f"{event.object} стал горячим"        # Действия перемещения        elif any(w in action for w in ("уронить", "бросить", "отпустить", "кинуть")):            event.before_state = "в руке"            event.after_state = "на земле"            event.effect = event.effect or f"{event.object} упал"        # Действия создания        elif any(w in action for w in ("создать", "сделать", "построить", "изготовить")):            event.before_state = "не существует"            event.after_state = "существует"            event.effect = event.effect or f"{event.object} создан"    def _infer_causal_links(self, event: EventModel):        """        Ищет в CausalGraph известные причинно-следственные связи.        """        if not event.action:            return        # Ищем последствия действия в графе        consequences = self.causal_graph.get_consequences(event.action)        if consequences:            # Добавляем первое найденное последствие как эффект,            # если эффект ещё не определён            if not event.effect:                event.effect = consequences[0].get("consequence")            # Если есть несколько — добавляем в related_events            for cons in consequences[1:]:                event.related_events.append(cons.get("consequence", ""))        # Ищем причины действия в графе        causes = self.causal_graph.get_causes(event.action)        if causes and not event.cause:            event.cause = causes[0].get("cause")